return [
  {
    json: {
      item_id: '6d6e2f96ab2c',
      source_type: 'rss',
      source_name: 'OpenAI YouTube',
      canonical_url: 'https://example.com/post',
      title: 'Example normalized item',
      published_at: '2026-04-17T09:00:00-04:00',
      content_text: 'Normalized plain text content for vector search.',
      content_hash: 'sha256:example',
      embedding_model: $env.EMBEDDING_MODEL || 'text-embedding-3-small',
      qdrant_collection: $env.QDRANT_COLLECTION || 'article_embeddings',
      tags: ['inbox', 'ai-information-processor'],
      status: 'enriched'
    }
  }
];

return {
  json: {
    ...$json,
    qdrant_search_payload: {
      collection: $json.qdrant_collection,
      vector_size: Number($env.QDRANT_VECTOR_SIZE || 1536),
      limit: 1,
      with_payload: true
    }
  }
};

return {
  json: {
    ...$json,
    qdrant_result: [
      {
        score: 0.91,
        payload: {
          item_id: 'existing-item',
          title: 'Existing similar item',
          canonical_url: 'https://example.com/existing'
        }
      }
    ]
  }
};

const match = $json.qdrant_result?.[0];

let dedupeAction = 'full_push';
if (match && match.score >= 0.97) {
  dedupeAction = 'silent';
} else if (match && match.score >= 0.85) {
  dedupeAction = 'diff_push';
}

return {
  json: {
    ...$json,
    dedupe_action: dedupeAction,
    matched_payload: match?.payload || null,
    matched_score: match?.score || 0,
    status: dedupeAction === 'silent' ? 'deduped' : $json.status
  }
};

return {
  json: {
    ...$json,
    qdrant_upsert_payload: {
      points: [
        {
          id: $json.item_id,
          vector: 'replace-with-real-embedding-vector',
          payload: {
            item_id: $json.item_id,
            title: $json.title,
            canonical_url: $json.canonical_url,
            published_at: $json.published_at,
            dedupe_action: $json.dedupe_action
          }
        }
      ]
    }
  }
};
